// ===== MAPEO DE DATOS DESDE TALLY (claves question_*) =====
const webhookData = $input.first().json;
const tallyFields = webhookData.body?.data?.fields || [];

// Helper: valor único (dropdown, single choice, text)
const getField = (key) => {
  const field = tallyFields.find(f => f.key === key);
  if (!field) return null;
  if (field.value && Array.isArray(field.value) && field.options) {
    const selected = field.options.find(opt => field.value.includes(opt.id));
    return selected ? selected.text : null;
  }
  return field.value != null ? String(field.value) : null;
};

// Helper: valores múltiples (checkboxes, multiple choice)
const getFields = (key) => {
  const field = tallyFields.find(f => f.key === key);
  if (!field) return [];
  if (field.value && Array.isArray(field.value) && field.options) {
    return field.options
      .filter(opt => field.value.includes(opt.id))
      .map(opt => opt.text);
  }
  if (Array.isArray(field.value)) return field.value;
  return field.value ? [String(field.value)] : [];
};

// ─── DATOS BÁSICOS ───────────────────────────────────────────────────────────
const nombre    = getField('question_KMvXRA') || '';
const apellidos = getField('question_7de71A') || '';
const email     = (getField('question_Ldv8oj') || '').toLowerCase().trim();
const telefono  = getField('question_pLRgZq') || '';
const edad      = parseInt(getField('question_1rDjBQ') || 0);

// ─── SEXO ────────────────────────────────────────────────────────────────────
const sexoRaw = (getField('question_MAv0Gp') || '').toLowerCase().trim();
const sexo = sexoRaw === 'masculino' ? 'masculino' : 'femenino';

// ─── MEDIDAS CORPORALES ──────────────────────────────────────────────────────
const peso_actual          = parseFloat(getField('question_J2XyB4') || 0);
const altura               = parseInt(getField('question_EPZ1kX') || 0);
const contorno_abdominal_1 = parseFloat(getField('question_MAy56l') || 0) || null;
const contorno_abdominal_2 = parseFloat(getField('question_J2Y0er') || 0) || null;
const contorno_abdominal_3 = parseFloat(getField('question_g5r4JP') || 0) || null;

// ─── OBJETIVO ────────────────────────────────────────────────────────────────
const objetivoRaw = (getField('question_rlJKjl') || '').toLowerCase().trim();
const objetivoMap = {
  'perder peso': 'perder_peso',
  'ganar masa muscular': 'ganar_masa',
  'definición': 'definicion',
  'definicion': 'definicion',
  'quiero comer bien': 'mantener'
};
const objetivo = objetivoMap[objetivoRaw] || 'mantener';

// ─── TIEMPO OBJETIVO ─────────────────────────────────────────────────────────
const tiempo_objetivo = getField('question_429k4k') || '';

// ─── NIVEL ACTIVIDAD ─────────────────────────────────────────────────────────
const actividadRaw = (getField('question_jBJMax') || '').toLowerCase().trim();
const actividadMap = {
  'trabajo de oficina, poco o nada de ejercicio': 'sedentario',
  'ejercicio ligero 1-2 días por semana': 'ligero',
  'ejercicio moderado 3-5 días por semana': 'moderado',
  'ejercicio intenso 6-7 días por semana': 'muy_activo'
};
const nivel_actividad = actividadMap[actividadRaw] || 'moderado';

// ─── ALERGIAS (múltiple selección) ───────────────────────────────────────────
const alergias_raw = getFields('question_24lkEL');
const alergias = alergias_raw.filter(a => a.toLowerCase() !== 'ninguna' && a.toLowerCase() !== 'otra');
const alergias_texto = getField('question_xdRQXy') || '';
if (alergias_texto.trim()) alergias.push(alergias_texto.trim());

// ─── INTOLERANCIAS (múltiple selección) ──────────────────────────────────────
const intolerancias_raw = getFields('question_Zd1Vjz');
const intolerancias = intolerancias_raw.filter(a => a.toLowerCase() !== 'ninguna' && a.toLowerCase() !== 'otra');
const intolerancias_texto = getField('question_NAbVpB') || '';
if (intolerancias_texto.trim() && intolerancias_texto !== 'null') {
  intolerancias.push(intolerancias_texto.trim());
}

// ─── COMIDAS DEL DÍA ─────────────────────────────────────────────────────────
const comidas_seleccionadas = getFields('question_Al0MAk');
const comidas_diarias = comidas_seleccionadas.length || 3;

// ─── PREFERENCIAS ALIMENTARIAS ───────────────────────────────────────────────
const dieta_anterior             = getField('question_blD1Ko') || '';
const alimentos_a_evitar         = getField('question_BGgJAN') || '';
const datos_interes              = getField('question_kYp8KM') || '';
const consume_alcohol            = getField('question_vNp8EQ') || '';
const consume_bebidas_azucaradas = getField('question_jBpNXE') || '';
const pica_entre_comidas         = getField('question_KMgrv7') || '';
const apetencias                 = getFields('question_Ldg4a1');
const notas_apetencias           = getField('question_QAp4r7') || '';
const consume_lacteos_raw        = (getField('question_pLMYJb') || '').toLowerCase();
const consume_lacteos            = consume_lacteos_raw === 'si' || consume_lacteos_raw === 'sí';
const bebidas_vegetales_raw      = getFields('question_24Z0zV');
const bebidas_vegetales_preferidas = bebidas_vegetales_raw.filter(v => !v.toLowerCase().includes('no me gustan'));
const proteinas_preferidas       = getFields('question_1rxQNW');
const notas_proteinas            = getField('question_MAgj6X') || '';
const consume_verduras           = getField('question_J2gEed') || '';
const carbohidratos_preferidos   = getFields('question_g5p8Jd');
const frutos_secos_raw           = getFields('question_ylG8o4');
const tipo_dieta_raw             = (getField('question_EPGzal') || 'No').trim();
const tipo_dieta_map             = { 'no': 'no', 'vegana': 'vegana', 'vegetariana': 'vegetariana' };
const tipo_dieta                 = tipo_dieta_map[tipo_dieta_raw.toLowerCase()] || 'no';
const frutos_secos_preferidos    = frutos_secos_raw.filter(v => !v.toLowerCase().includes('prefiero evitarlos'));

// ─── VALORES FIJOS ───────────────────────────────────────────────────────────
const patologias          = [];
const medicacion          = '';
const presupuesto_semanal = null;

return [{
  json: {
    cliente: {
      nombre, apellidos, email, telefono, edad, sexo,
      peso_actual, altura,
      contorno_abdominal_1, contorno_abdominal_2, contorno_abdominal_3,
      objetivo, tiempo_objetivo, nivel_actividad,
      alergias, intolerancias,
      comidas_diarias, comidas_seleccionadas,
      dieta_anterior, alimentos_a_evitar, datos_interes,
      consume_alcohol, consume_bebidas_azucaradas, pica_entre_comidas,
      apetencias, notas_apetencias,
      consume_lacteos, bebidas_vegetales_preferidas,
      proteinas_preferidas, notas_proteinas,
      consume_verduras, carbohidratos_preferidos, frutos_secos_preferidos,
      patologias, medicacion, presupuesto_semanal,
      tipo_dieta
    },
    metadata: {
      id_solicitud: 'SOL-' + Date.now(),
      timestamp: new Date().toISOString(),
      responseId: webhookData.body?.data?.responseId,
      formId: webhookData.body?.data?.formId
    }
  }
}];

const item = $input.first().json;
const c = item.cliente;

// TMB Mifflin-St Jeor
const tmb = c.sexo === 'masculino'
  ? (10 * c.peso_actual) + (6.25 * c.altura) - (5 * c.edad) + 5
  : (10 * c.peso_actual) + (6.25 * c.altura) - (5 * c.edad) - 161;

// TDEE
const factores = { sedentario:1.2, ligero:1.375, moderado:1.55, activo:1.725, muy_activo:1.9 };
const tdee = tmb * (factores[c.nivel_actividad] || 1.375);

// Ajuste por objetivo
const ajustes = { perder_peso:-0.20, ganar_masa:0.15, mantener:0, definicion:-0.10 };
const cal_objetivo = Math.round(tdee * (1 + (ajustes[c.objetivo] || 0)));

// Macros
const factorProt = c.objetivo === 'ganar_masa' ? 2.2 : 1.8;
const proteinas_g = Math.round(c.peso_actual * factorProt);
const grasas_g = Math.round((cal_objetivo * 0.28) / 9);
const carbos_g = Math.round((cal_objetivo - (proteinas_g * 4) - (grasas_g * 9)) / 4);

// IMC
const imc = parseFloat((c.peso_actual / Math.pow(c.altura/100, 2)).toFixed(1));
const imc_cat = imc < 18.5 ? 'Bajo peso' : imc < 25 ? 'Normal' : imc < 30 ? 'Sobrepeso' : 'Obesidad';

// Rangos ±5%
const rango = (v, p=0.05) => ({ min: Math.round(v*(1-p)), max: Math.round(v*(1+p)) });

// Alertas
const alertas = [];
if (cal_objetivo < 1200) alertas.push('ALERTA: Calorías muy bajas (<1200 kcal)');
if (imc < 17 || imc > 40) alertas.push('ALERTA: IMC extremo - requiere supervisión médica');
if (c.patologias && c.patologias.length > 0) alertas.push(`AVISO: Patologías declaradas: ${c.patologias.join(', ')}`);
if (c.peso_objetivo && Math.abs(c.peso_actual - c.peso_objetivo) > 15) alertas.push('AVISO: Objetivo de peso agresivo (>15kg)');

// Proyección
const diff_kg = Math.abs(c.peso_actual - (c.peso_objetivo || c.peso_actual));
const semanas_objetivo = c.objetivo === 'perder_peso' ? Math.ceil(diff_kg / 0.7) : Math.ceil(diff_kg / 0.4);

return [{
  json: {
    ...item,
    cliente: { ...c, imc, imc_categoria: imc_cat },
    calculos: {
      tmb: Math.round(tmb),
      tdee: Math.round(tdee),
      imc,
      imc_categoria: imc_cat,
      objetivo: { calorias: cal_objetivo, proteinas_g, carbohidratos_g: carbos_g, grasas_g },
      rangos: {
        calorias: rango(cal_objetivo),
        proteinas: rango(proteinas_g),
        carbohidratos: rango(carbos_g),
        grasas: rango(grasas_g)
      },
      proyeccion: { semanas_estimadas: semanas_objetivo, fecha_objetivo: new Date(Date.now() + semanas_objetivo*7*24*3600*1000).toISOString().split('T')[0] },
      alertas
    }
  }
}];

// Verificar si la sesión de Stripe ha expirado (>23 horas)
const cliente = $input.first().json;
const sessionId = cliente.stripe_session_id;

if (!sessionId) {
  // Sin sesión → flujo normal (crear nueva)
  return [{ json: cliente }];
}

// Comprobar antigüedad usando fecha_solicitud
const fechaSolicitud = cliente.fecha_solicitud ? new Date(cliente.fecha_solicitud) : null;
const ahora = new Date();
