  ? (ahora - fechaSolicitud) / (1000 * 60 * 60)
  : 999;

if (horasTranscurridas > 23) {
  // Sesión expirada → limpiarla para que se cree una nueva
  return [{ json: { ...cliente, stripe_session_id: null, _session_expirada: true } }];
}

// Sesión válida → mantenerla
return [{ json: { ...cliente, _session_expirada: false } }];
